#include <bits/stdc++.h>
using namespace std;
#define int long long
const int N = 1e6 + 3;;
int n, m, a[N];
int dat[N * 24], ls[N * 24], rs[N * 24], tot;
int root[N];
void build(int &p, int lp, int rp) {
    p = ++tot;
    if(lp == rp) { dat[p] = a[lp]; return; }
    int mid = (lp + rp) >> 1;
    build(ls[p], lp, mid);
    build(rs[p], mid + 1, rp);
}
void update(int &p, int pre, int lp, int rp, int x, int v) {
    p = ++tot;
    ls[p] = ls[pre]; rs[p] = rs[pre];
    if(lp == rp) { dat[p] = v; return; }
    int mid = (lp + rp) >> 1;
    if(x <= mid) update(ls[p], ls[pre], lp, mid, x, v);
    else update(rs[p], rs[pre], mid + 1, rp, x, v);
}
int query(int p, int lp, int rp, int x) {
    if(lp == rp) return dat[p];
    int mid = (lp + rp) >> 1;
    if(x <= mid) return query(ls[p], lp, mid, x);
    else return query(rs[p], mid + 1, rp, x);
}
signed main() {
    ios::sync_with_stdio(0); cin.tie(0); cout.tie(0);
    cin >> n >> m;
    for(int i = 1; i <= n; i++) cin >> a[i];
    build(root[0], 1, n);
    for(int i = 1; i <= m; i++) {
        int v, op, p, c;
        cin >> v >> op >> p;
        if(op == 1) { cin >> c; update(root[i], root[v], 1, n, p, c); }
        else { cout << query(root[v], 1, n, p) << '\n'; root[i] = root[v]; }
    }
    return 0;
}
